341	          .filter((entry) => isChannelTarget(entry))
342	          .join(", "),
343	      applySet: async ({ cfg, accountId, value }) => {
344	        const channels = parseListInput(String(value))
345	          .map((entry) => normalizeGroupEntry(entry))
346	          .filter((entry): entry is string => Boolean(entry && entry !== "*"))
347	          .filter((entry) => isChannelTarget(entry));
348	        return updateIrcAccountConfig(cfg as CoreConfig, accountId, {
349	          enabled: true,
350	          channels: channels.length > 0 ? channels : undefined,
351	        });
352	      },
