362	    updatePrompt: ({ cfg, accountId }) =>
363	      Boolean(resolveIrcAccount({ cfg: cfg as CoreConfig, accountId }).config.groups),
364	    setPolicy: ({ cfg, accountId, policy }) =>
365	      setIrcGroupAccess(cfg as CoreConfig, accountId, policy, [], normalizeGroupEntry),
366	    resolveAllowlist: async ({ entries }) =>
367	      [...new Set(entries.map((entry) => normalizeGroupEntry(entry)).filter(Boolean))] as string[],
368	    applyAllowlist: ({ cfg, accountId, resolved }) =>
369	      setIrcGroupAccess(
370	        cfg as CoreConfig,
371	        accountId,
372	        "allowlist",
373	        resolved as string[],
374	        normalizeGroupEntry,
