412	            ]),
413	          );
414	          next = updateIrcAccountConfig(next, accountId, { groups: patched });
415	        }
416	      }
417	    }
418	
419	    next = await promptIrcNickServConfig({
420	      cfg: next,
421	      prompter,
422	      accountId,
423	    });
424	    return { cfg: next };
425	  },
426	  completionNote: {
427	    title: "IRC next steps",
428	    lines: [
429	      "Next: restart gateway and verify status.",
430	      "Command: openclaw channels status --probe",
