1	import { createAccountListHelpers } from "openclaw/plugin-sdk/account-helpers";
2	import { DEFAULT_ACCOUNT_ID, normalizeAccountId } from "openclaw/plugin-sdk/account-id";
3	import { resolveMergedAccountConfig } from "openclaw/plugin-sdk/account-resolution";
4	import { parseOptionalDelimitedEntries } from "openclaw/plugin-sdk/core";
5	import { tryReadSecretFileSync } from "openclaw/plugin-sdk/core";
6	import { normalizeResolvedSecretInputString } from "openclaw/plugin-sdk/secret-input";
7	import type { CoreConfig, IrcAccountConfig, IrcNickServConfig } from "./types.js";
8	
9	const TRUTHY_ENV = new Set(["true", "1", "yes", "on"]);
10	
11	export type ResolvedIrcAccount = {
12	  accountId: string;
13	  enabled: boolean;
14	  name?: string;
15	  configured: boolean;
16	  host: string;
17	  port: number;
18	  tls: boolean;
19	  nick: string;
20	  username: string;
21	  realname: string;
22	  password: string;
23	  passwordSource: "env" | "passwordFile" | "config" | "none";
24	  config: IrcAccountConfig;
25	};
26	
27	function parseTruthy(value?: string): boolean {
28	  if (!value) {
29	    return false;
30	  }
31	  return TRUTHY_ENV.has(value.trim().toLowerCase());
32	}
33	
34	function parseIntEnv(value?: string): number | undefined {
35	  if (!value?.trim()) {
36	    return undefined;
37	  }
38	  const parsed = Number.parseInt(value.trim(), 10);
39	  if (!Number.isFinite(parsed) || parsed <= 0 || parsed > 65535) {
40	    return undefined;
41	  }
42	  return parsed;
43	}
44	
45	const { listAccountIds: listIrcAccountIds, resolveDefaultAccountId: resolveDefaultIrcAccountId } =
46	  createAccountListHelpers("irc", { normalizeAccountId });
47	export { listIrcAccountIds, resolveDefaultIrcAccountId };
48	
49	function mergeIrcAccountConfig(cfg: CoreConfig, accountId: string): IrcAccountConfig {
50	  return resolveMergedAccountConfig<IrcAccountConfig>({
51	    channelConfig: cfg.channels?.irc as IrcAccountConfig | undefined,
52	    accounts: cfg.channels?.irc?.accounts as Record<string, Partial<IrcAccountConfig>> | undefined,
53	    accountId,
54	    omitKeys: ["defaultAccount"],
55	    normalizeAccountId,
56	    nestedObjectKeys: ["nickserv"],
57	  });
58	}
59	
60	function resolvePassword(accountId: string, merged: IrcAccountConfig) {
61	  if (accountId === DEFAULT_ACCOUNT_ID) {
62	    const envPassword = process.env.IRC_PASSWORD?.trim();
63	    if (envPassword) {
64	      return { password: envPassword, source: "env" as const };
65	    }
66	  }
67	
68	  if (merged.passwordFile?.trim()) {
69	    const filePassword = tryReadSecretFileSync(merged.passwordFile, "IRC password file", {
70	      rejectSymlink: true,
71	    });
72	    if (filePassword) {
73	      return { password: filePassword, source: "passwordFile" as const };
74	    }
75	  }
76	
77	  const configPassword = normalizeResolvedSecretInputString({
78	    value: merged.password,
79	    path: `channels.irc.accounts.${accountId}.password`,
80	  });
81	  if (configPassword) {
82	    return { password: configPassword, source: "config" as const };
83	  }
84	
85	  return { password: "", source: "none" as const };
86	}
87	
88	function resolveNickServConfig(accountId: string, nickserv?: IrcNickServConfig): IrcNickServConfig {
89	  const base = nickserv ?? {};
90	  const envPassword =
91	    accountId === DEFAULT_ACCOUNT_ID ? process.env.IRC_NICKSERV_PASSWORD?.trim() : undefined;
92	  const envRegisterEmail =
93	    accountId === DEFAULT_ACCOUNT_ID ? process.env.IRC_NICKSERV_REGISTER_EMAIL?.trim() : undefined;
94	
95	  const passwordFile = base.passwordFile?.trim();
96	  let resolvedPassword =
97	    normalizeResolvedSecretInputString({
98	      value: base.password,
99	      path: `channels.irc.accounts.${accountId}.nickserv.password`,
100	    }) ||
101	    envPassword ||
102	    "";
103	  if (!resolvedPassword && passwordFile) {
104	    resolvedPassword =
105	      tryReadSecretFileSync(passwordFile, "IRC NickServ password file", {
106	        rejectSymlink: true,
107	      }) ?? "";
108	  }
109	
110	  const merged: IrcNickServConfig = {
111	    ...base,
112	    service: base.service?.trim() || undefined,
113	    passwordFile: passwordFile || undefined,
114	    password: resolvedPassword || undefined,
115	    registerEmail: base.registerEmail?.trim() || envRegisterEmail || undefined,
116	  };
117	  return merged;
118	}
119	
120	export function resolveIrcAccount(params: {
121	  cfg: CoreConfig;
122	  accountId?: string | null;
123	}): ResolvedIrcAccount {
124	  const hasExplicitAccountId = Boolean(params.accountId?.trim());
125	  const baseEnabled = params.cfg.channels?.irc?.enabled !== false;
126	
127	  const resolve = (accountId: string) => {
128	    const merged = mergeIrcAccountConfig(params.cfg, accountId);
129	    const accountEnabled = merged.enabled !== false;
130	    const enabled = baseEnabled && accountEnabled;
131	
132	    const tls =
133	      typeof merged.tls === "boolean"
134	        ? merged.tls
135	        : accountId === DEFAULT_ACCOUNT_ID && process.env.IRC_TLS
136	          ? parseTruthy(process.env.IRC_TLS)
137	          : true;
138	
139	    const envPort =
140	      accountId === DEFAULT_ACCOUNT_ID ? parseIntEnv(process.env.IRC_PORT) : undefined;
141	    const port = merged.port ?? envPort ?? (tls ? 6697 : 6667);
142	    const envChannels =
143	      accountId === DEFAULT_ACCOUNT_ID
144	        ? parseOptionalDelimitedEntries(process.env.IRC_CHANNELS)
145	        : undefined;
146	
147	    const host = (
148	      merged.host?.trim() ||
149	      (accountId === DEFAULT_ACCOUNT_ID ? process.env.IRC_HOST?.trim() : "") ||
150	      ""
151	    ).trim();
152	    const nick = (
153	      merged.nick?.trim() ||
154	      (accountId === DEFAULT_ACCOUNT_ID ? process.env.IRC_NICK?.trim() : "") ||
155	      ""
156	    ).trim();
157	    const username = (
158	      merged.username?.trim() ||
159	      (accountId === DEFAULT_ACCOUNT_ID ? process.env.IRC_USERNAME?.trim() : "") ||
160	      nick ||
161	      "openclaw"
162	    ).trim();
163	    const realname = (
164	      merged.realname?.trim() ||
165	      (accountId === DEFAULT_ACCOUNT_ID ? process.env.IRC_REALNAME?.trim() : "") ||
166	      "OpenClaw"
167	    ).trim();
168	
169	    const passwordResolution = resolvePassword(accountId, merged);
170	    const nickserv = resolveNickServConfig(accountId, merged.nickserv);
171	
172	    const config: IrcAccountConfig = {
173	      ...merged,
174	      channels: merged.channels ?? envChannels,
175	      tls,
176	      port,
177	      host,
178	      nick,
179	      username,
180	      realname,
181	      nickserv,
182	    };
183	
184	    return {
185	      accountId,
186	      enabled,
187	      name: merged.name?.trim() || undefined,
188	      configured: Boolean(host && nick),
189	      host,
190	      port,
191	      tls,
192	      nick,
193	      username,
194	      realname,
195	      password: passwordResolution.password,
196	      passwordSource: passwordResolution.source,
197	      config,
198	    } satisfies ResolvedIrcAccount;
199	  };
200	
201	  const normalized = normalizeAccountId(params.accountId);
202	  const primary = resolve(normalized);
203	  if (hasExplicitAccountId) {
204	    return primary;
205	  }
206	  if (primary.configured) {
207	    return primary;
208	  }
209	
210	  const fallbackId = resolveDefaultIrcAccountId(params.cfg);
211	  if (fallbackId === primary.accountId) {
212	    return primary;
213	  }
214	  const fallback = resolve(fallbackId);
215	  if (!fallback.configured) {
216	    return primary;
217	  }
218	  return fallback;
219	}
220	
221	export function listEnabledIrcAccounts(cfg: CoreConfig): ResolvedIrcAccount[] {
222	  return listIrcAccountIds(cfg)
223	    .map((accountId) => resolveIrcAccount({ cfg, accountId }))
224	    .filter((account) => account.enabled);
225	}
