1	import { resolveMarkdownTableMode } from "openclaw/plugin-sdk/config-runtime";
2	import { convertMarkdownTables } from "openclaw/plugin-sdk/text-runtime";
3	import { resolveIrcAccount } from "./accounts.js";
4	import type { IrcClient } from "./client.js";
5	import { connectIrcClient } from "./client.js";
6	import { buildIrcConnectOptions } from "./connect-options.js";
7	import { normalizeIrcMessagingTarget } from "./normalize.js";
8	import { makeIrcMessageId } from "./protocol.js";
9	import { getIrcRuntime } from "./runtime.js";
10	import type { CoreConfig } from "./types.js";
11	
12	type SendIrcOptions = {
13	  cfg?: CoreConfig;
14	  accountId?: string;
15	  replyTo?: string;
16	  target?: string;
17	  client?: IrcClient;
18	};
19	
20	export type SendIrcResult = {
21	  messageId: string;
22	  target: string;
23	};
24	
25	function recordIrcOutboundActivity(accountId: string): void {
26	  try {
27	    getIrcRuntime().channel.activity.record({
28	      channel: "irc",
29	      accountId,
30	      direction: "outbound",
31	    });
32	  } catch (error) {
33	    if (!(error instanceof Error) || error.message !== "IRC runtime not initialized") {
34	      throw error;
35	    }
36	  }
37	}
38	
39	function resolveTarget(to: string, opts?: SendIrcOptions): string {
40	  const fromArg = normalizeIrcMessagingTarget(to);
41	  if (fromArg) {
42	    return fromArg;
43	  }
44	  const fromOpt = normalizeIrcMessagingTarget(opts?.target ?? "");
45	  if (fromOpt) {
46	    return fromOpt;
47	  }
48	  throw new Error(`Invalid IRC target: ${to}`);
49	}
50	
51	export async function sendMessageIrc(
52	  to: string,
53	  text: string,
54	  opts: SendIrcOptions = {},
55	): Promise<SendIrcResult> {
56	  const runtime = getIrcRuntime();
57	  const cfg = (opts.cfg ?? runtime.config.loadConfig()) as CoreConfig;
58	  const account = resolveIrcAccount({
59	    cfg,
60	    accountId: opts.accountId,
61	  });
62	
63	  if (!account.configured) {
64	    throw new Error(
65	      `IRC is not configured for account "${account.accountId}" (need host and nick in channels.irc).`,
66	    );
67	  }
68	
69	  const target = resolveTarget(to, opts);
70	  const tableMode = resolveMarkdownTableMode({
71	    cfg,
72	    channel: "irc",
73	    accountId: account.accountId,
74	  });
75	  const prepared = convertMarkdownTables(text.trim(), tableMode);
76	  const payload = opts.replyTo ? `${prepared}\n\n[reply:${opts.replyTo}]` : prepared;
77	
78	  if (!payload.trim()) {
79	    throw new Error("Message must be non-empty for IRC sends");
80	  }
81	
82	  const client = opts.client;
83	  if (client?.isReady()) {
84	    client.sendPrivmsg(target, payload);
85	  } else {
86	    const transient = await connectIrcClient(
87	      buildIrcConnectOptions(account, {
88	        connectTimeoutMs: 12000,
89	      }),
90	    );
91	    transient.sendPrivmsg(target, payload);
92	    transient.quit("sent");
93	  }
94	
95	  recordIrcOutboundActivity(account.accountId);
96	
97	  return {
98	    messageId: makeIrcMessageId(),
99	    target,
100	  };
101	}
