export {
  createAccountStatusSink,
  runPassiveAccountLifecycle,
} from "openclaw/plugin-sdk/channel-lifecycle";
export { getChatChannelMeta } from "openclaw/plugin-sdk/core";
export type { ChannelPlugin, OpenClawConfig } from "openclaw/plugin-sdk/core";
export { DEFAULT_ACCOUNT_ID } from "openclaw/plugin-sdk/account-id";
export type { PluginRuntime } from "openclaw/plugin-sdk/runtime-store";
export type { DmPolicy, GroupPolicy } from "openclaw/plugin-sdk/setup";
export type { OutboundReplyPayload } from "openclaw/plugin-sdk/reply-payload";
export type { RuntimeEnv } from "openclaw/plugin-sdk/runtime-env";
export {
  buildBaseChannelStatusSummary,
  createComputedAccountStatusAdapter,
  createDefaultChannelRuntimeState,
} from "openclaw/plugin-sdk/status-helpers";

/**
 * Chunk outbound text while preferring newline and space boundaries.
 *
 * chunkTextForOutbound is not available from a public SDK subpath; this
 * implementation mirrors the shared text-chunker logic used by other bundled
 * channel plugins.
 */
export function chunkTextForOutbound(text: string, limit: number): string[] {
  if (!text) {
    return [];
  }
  if (limit <= 0 || text.length <= limit) {
    return [text];
  }
  const chunks: string[] = [];
  let remaining = text;
  while (remaining.length > limit) {
    const window = remaining.slice(0, limit);
    const lastNewline = window.lastIndexOf("\n");
    const lastSpace = window.lastIndexOf(" ");
    const candidateBreak = lastNewline > 0 ? lastNewline : lastSpace;
    const breakIdx =
      Number.isFinite(candidateBreak) && candidateBreak > 0 && candidateBreak <= limit
        ? candidateBreak
        : limit;
    const chunk = remaining.slice(0, breakIdx).trimEnd();
    if (chunk.length > 0) {
      chunks.push(chunk);
    }
    const brokeOnSeparator = breakIdx < remaining.length && /\s/.test(remaining[breakIdx] ?? "");
    const nextStart = Math.min(remaining.length, breakIdx + (brokeOnSeparator ? 1 : 0));
    remaining = remaining.slice(nextStart).trimStart();
  }
  if (remaining.length > 0) {
    chunks.push(remaining);
  }
  return chunks;
}

