import type { DmPolicy, GroupPolicy, OpenClawConfig } from "./runtime-api.js";

// Local type aliases for structural config types that are not available from
// public SDK subpaths.  These mirror the shapes used by core and other bundled
// channel plugins.

export type GroupToolPolicyConfig = {
  allow?: string[];
  /** Additional allowlist entries merged into allow. */
  alsoAllow?: string[];
  deny?: string[];
};

export type GroupToolPolicyBySenderConfig = Record<string, GroupToolPolicyConfig | undefined>;

export type BlockStreamingCoalesceConfig = {
  minChars?: number;
  maxChars?: number;
  idleMs?: number;
};

export type DmConfig = {
  historyLimit?: number;
};

export type MarkdownConfig = {
  tables?: string;
};

export type BaseProbeResult<TError = string | null> = {
  ok: boolean;
  error?: TError;
};

/** Per-board (group) configuration overrides. */
export type PulseBoardBoardConfig = {
  requireMention?: boolean;
  tools?: GroupToolPolicyConfig;
  toolsBySender?: GroupToolPolicyBySenderConfig;
  skills?: string[];
  enabled?: boolean;
  allowFrom?: Array<string | number>;
  systemPrompt?: string;
};

/** Account-level configuration for a PulseBoard connection. */
export type PulseBoardAccountConfig = {
  name?: string;
  enabled?: boolean;
  /** Base URL of the PulseBoard API (example: https://pulseboard.example.com/api). */
  apiUrl?: string;
  /** Bearer token for API authentication. */
  token?: string;
  /** Path to a file containing the bearer token. */
  tokenFile?: string;
  /** Bot username on PulseBoard. */
  username?: string;
  dmPolicy?: DmPolicy;
  allowFrom?: Array<string | number>;
  defaultTo?: string;
  groupPolicy?: GroupPolicy;
  groupAllowFrom?: Array<string | number>;
  /** Per-board config overrides, keyed by #board-name. */
  boards?: Record<string, PulseBoardBoardConfig>;
  /** Board names to auto-subscribe on connect. */
  subscribeBoards?: string[];
  mentionPatterns?: string[];
  markdown?: MarkdownConfig;
  historyLimit?: number;
  dmHistoryLimit?: number;
  dms?: Record<string, DmConfig>;
  textChunkLimit?: number;
  blockStreaming?: boolean;
  blockStreamingCoalesce?: BlockStreamingCoalesceConfig;
  mediaMaxMb?: number;
};

export type PulseBoardConfig = PulseBoardAccountConfig & {
  accounts?: Record<string, PulseBoardAccountConfig>;
  defaultAccount?: string;
};

export type CoreConfig = OpenClawConfig & {
  channels?: OpenClawConfig["channels"] & {
    pulseboard?: PulseBoardConfig;
  };
};

export type PulseBoardInboundMessage = {
  messageId: string;
  /** Conversation peer id: #board-name for groups, sender username for DMs. */
  target: string;
  senderUsername: string;
  text: string;
  timestamp: number;
  isGroup: boolean;
};

export type PulseBoardProbe = BaseProbeResult<string> & {
  apiUrl: string;
  username: string;
  latencyMs?: number;
};

