import { afterEach, describe, expect, it } from "vitest";
import { pulseBoardPlugin } from "./channel.js";
import { clearPulseBoardRuntime } from "./runtime.js";

describe("pulseboard plugin", () => {
  afterEach(() => {
    clearPulseBoardRuntime();
  });

  it("has the correct plugin id", () => {
    expect(pulseBoardPlugin.id).toBe("pulseboard");
  });

  it("supports direct and group chat types", () => {
    const chatTypes = pulseBoardPlugin.capabilities?.chatTypes ?? [];
    expect(chatTypes).toContain("direct");
    expect(chatTypes).toContain("group");
  });

  it("has textChunkLimit of 4000", () => {
    expect(pulseBoardPlugin.outbound?.textChunkLimit).toBe(4000);
  });

  it("chunks outbound text without requiring PulseBoard runtime initialization", () => {
    const chunker = pulseBoardPlugin.outbound?.chunker;
    if (!chunker) {
      throw new Error("pulseboard outbound.chunker unavailable");
    }

    // Basic word-boundary chunking.
    expect(chunker("alpha beta", 5)).toEqual(["alpha", "beta"]);
  });

  it("chunks long text at newline boundaries when possible", () => {
    const chunker = pulseBoardPlugin.outbound?.chunker;
    if (!chunker) {
      throw new Error("pulseboard outbound.chunker unavailable");
    }

    const line1 = "a".repeat(10);
    const line2 = "b".repeat(10);
    const text = `${line1}\n${line2}`;
    // Both lines fit within limit=4000; returned as one chunk.
    const chunks = chunker(text, 4000);
    expect(chunks).toHaveLength(1);
    expect(chunks[0]).toBe(text);
  });

  it("does not chunk text shorter than textChunkLimit", () => {
    const chunker = pulseBoardPlugin.outbound?.chunker;
    if (!chunker) {
      throw new Error("pulseboard outbound.chunker unavailable");
    }

    const short = "Hello, PulseBoard!";
    expect(chunker(short, 4000)).toEqual([short]);
  });
});

