    const chunker = pulseBoardPlugin.outbound?.chunker;
    if (!chunker) {
      throw new Error("pulseboard outbound.chunker unavailable");
    }

    const line1 = "a".repeat(10);
    const line2 = "b".repeat(10);
    const text = `${line1}\n${line2}`;
    // Both lines fit within limit=4000; returned as one chunk.
    const chunks = chunker(text, 4000);
    expect(chunks).toHaveLength(1);
    expect(chunks[0]).toBe(text);
  });

  it("does not chunk text shorter than textChunkLimit", () => {
    const chunker = pulseBoardPlugin.outbound?.chunker;
    if (!chunker) {
      throw new Error("pulseboard outbound.chunker unavailable");
    }

    const short = "Hello, PulseBoard!";
    expect(chunker(short, 4000)).toEqual([short]);
  });
});

